def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity < 0:
            priorities[i] = np.inf
            continue
        if capacity == 0:
            priorities[i] = 0 if item == 0 else np.inf
            continue
        ratio = item / capacity
        if ratio == 0:
            priorities[i] = 0
            continue
        if ratio < 0:
            priorities[i] = np.inf
            continue
        score = 0
        for n in range(1, 8):
            if n % 2 == 0:
                score -= (ratio ** n) / (n ** 1.5)
            else:
                score += (ratio ** n) / np.sqrt(n)
        penalty = 0
        for p in range(1, 5):
            temp = ratio ** (p + 2)
            if temp > 1:
                penalty += temp / (p * (p + 1))
            else:
                penalty += temp * (p ** 2)
        if ratio > 2:
            extra_penalty = 0
            for q in range(1, 4):
                extra_penalty += (ratio ** (q*2)) / (q + ratio)
            priorities[i] = score * np.log1p(ratio) + penalty + extra_penalty
        elif 1 < ratio <= 2:
            val = penalty * np.exp(-ratio)
            for r in range(1, 5):
                if r % 2 == 1:
                    val += (np.sin(r * ratio) / r)
                else:
                    val -= (np.cos(r * ratio) / r)
            priorities[i] = abs(score) + val
        elif 0 < ratio <= 1:
            val = score + penalty
            if ratio > 0.7:
                for s in range(1, 5):
                    val += ((-1) ** s) * ((ratio ** (s + 1)) / (s + 1))
            priorities[i] = abs(val)
        else:
            priorities[i] = np.inf
    return priorities
